#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int pid;
    int arrival;
    int burst;
    int priority;
    int remaining;
    int waiting;
    int turnaround;
    int response;
    int completed;
} Process;

void priority_scheduling(Process processes[], int n) {
    int current_time = 0;
    int completed = 0;
    int total_waiting = 0, total_turnaround = 0;

    printf("\n=== Priority Scheduling (Preemptive) ===\n");
    printf("Gantt Chart: ");

    while (completed < n) {
        // Find highest priority process in ready queue
        int highest_priority = 9999;
        int selected_index = -1;

        for (int i = 0; i < n; i++) {
            if (processes[i].arrival <= current_time && 
                !processes[i].completed &&
                processes[i].priority < highest_priority) {
                highest_priority = processes[i].priority;
                selected_index = i;
            }
        }

        if (selected_index == -1) {
            current_time++;
            continue;
        }

        // Record response time
        if (processes[selected_index].remaining == processes[selected_index].burst) {
            processes[selected_index].response = current_time - processes[selected_index].arrival;
        }

        // Execute for 1 time unit (preemptive)
        printf("P%d ", processes[selected_index].pid);
        processes[selected_index].remaining--;
        current_time++;

        // Check if process completed
        if (processes[selected_index].remaining == 0) {
            processes[selected_index].completed = 1;
            processes[selected_index].turnaround = current_time - processes[selected_index].arrival;
            processes[selected_index].waiting = processes[selected_index].turnaround - processes[selected_index].burst;
            completed++;
        }
    }

    // Calculate totals
    for (int i = 0; i < n; i++) {
        total_waiting += processes[i].waiting;
        total_turnaround += processes[i].turnaround;
    }

    printf("\n\nProcess\tPriority\tWaiting\tTurnaround\n");
    for (int i = 0; i < n; i++) {
        printf("P%d\t%d\t\t%d\t\t%d\n", 
               processes[i].pid, processes[i].priority,
               processes[i].waiting, processes[i].turnaround);
    }

    printf("\nAverage Waiting Time: %.2f", (float)total_waiting/n);
    printf("\nAverage Turnaround Time: %.2f\n", (float)total_turnaround/n);
}

int main() {
    int n = 4;
    Process processes[] = {
        {1, 0, 8, 3, 8, 0, 0, 0, 0},
        {2, 1, 4, 1, 4, 0, 0, 0, 0},
        {3, 2, 2, 4, 2, 0, 0, 0, 0},
        {4, 3, 6, 2, 6, 0, 0, 0, 0}
    };

    priority_scheduling(processes, n);
    return 0;
}
